/**
 * useWindowSize Hook
 * 
 * React hook for tracking window size with SSR safety.
 * Uses DOM utilities for safe window access.
 */

import { useState, useEffect } from 'react';
import { getWindowWidth, getWindowHeight, addWindowEventListener } from '@/shared/utils/dom/domUtils.js';

/**
 * Hook to track window size
 * 
 * @param {Object} options - Options
 * @param {boolean} [options.trackHeight=false] - Whether to track height
 * @returns {Object} Window size object { width, height }
 */
export const useWindowSize = (options = {}) => {
  const { trackHeight = false } = options;

  const [size, setSize] = useState({
    width: getWindowWidth(),
    height: trackHeight ? getWindowHeight() : 0,
  });

  useEffect(() => {
    const handleResize = () => {
      setSize({
        width: getWindowWidth(),
        height: trackHeight ? getWindowHeight() : 0,
      });
    };

    const cleanup = addWindowEventListener('resize', handleResize);
    
    // Call once to set initial size
    handleResize();

    return cleanup;
  }, [trackHeight]);

  return size;
};

export default useWindowSize;

